#!/bin/sh
# Clock app backend: emits the bundle.clock projection and the clock page as
# framed JSON effects on stdout. The process never sees NATS — the platform
# decides what materializes.
LC_ALL=C
export LC_ALL
json_escape() {
  printf '%s' "$1" | sed 's/\\/\\\\/g; s/"/\\"/g'
}
now=$(date -u +%Y-%m-%dT%H:%M:%SZ)
secs=$(date +%s)
ms=$(date +%s%3N)
page="<!doctype html><html><head><meta charset=utf-8><title>tinkabot sequence</title><style>body{font-family:Inter,ui-sans-serif,system-ui,sans-serif;margin:0;background:#f8fafc;color:#111827;line-height:1.45}main{max-width:1420px;margin:0 auto;padding:24px}h1{font-size:28px;margin:0 0 8px}p{margin:0 0 18px;color:#475569}.diagram{background:#fff;border:1px solid #cbd5e1;border-radius:6px;padding:16px;overflow:auto}.mermaid,.diagram svg{min-width:1320px}pre#s{font-family:ui-monospace,SFMono-Regular,Consolas,monospace;background:#0f172a;color:#e2e8f0;border-radius:6px;padding:16px;overflow:auto;min-height:220px}h2{font-size:18px;margin:22px 0 8px}@media(max-width:760px){main{padding:16px}.diagram{padding:10px}.mermaid,.diagram svg{min-width:980px}}</style><script type=module>import mermaid from 'https://cdn.jsdelivr.net/npm/mermaid@11.15.0/dist/mermaid.esm.min.mjs';mermaid.initialize({startOnLoad:true,theme:'base',securityLevel:'strict',themeVariables:{fontSize:'15px',fontFamily:'Inter, ui-sans-serif, system-ui, sans-serif'}});</script></head><body><main><h1>tinkabot sequence</h1><p>This Mermaid diagram is loaded from jsDelivr by the generated bundle UI. The live projection below is the same NATS-backed chain updating in realtime.</p><section class=diagram><pre class=mermaid>sequenceDiagram&#10;participant User as User or LLM&#10;participant TL as Tinkalet&#10;participant TB as Tinkabot&#10;participant NATS as NATS material&#10;participant Bundle as Bundle scripts&#10;participant Shell as Trusted shell&#10;participant UI as Generated UI&#10;User->>TB: Start an app bundle&#10;TB->>NATS: Derive accounts, subjects, projections, and artifacts&#10;TB->>Bundle: Run boot, tick, and watched transforms&#10;Bundle-->>TB: Emit framed effects for state, view, and page&#10;TB->>NATS: Materialize durable projections and artifacts&#10;Shell->>NATS: Read derived material with shell-owned authority&#10;Shell-->>UI: Deliver mediated state, no raw NATS credentials&#10;User->>TL: Send trigger, item, reaction, or schedule intent&#10;TL->>TB: Use selected profile authority&#10;TB->>NATS: Accept, route, audit, and materialize&#10;Shell-->>UI: Render the next NATS-backed view</pre></section><h2>live projection</h2><pre id=s>loading...</pre></main><script>let busy=false,last=0,seen=0;async function r(){if(busy){requestAnimationFrame(r);return}busy=true;const start=performance.now();const now=Date.now();try{const x=await fetch('_p/view?cache='+now,{cache:'no-store'});const env=await x.json();const view=env.value||env;const seq=view.seq||env.sequence;const ms=view.ms||view.tick;const after=Date.now();if(seq&&seq!==last){last=seq;seen++}document.getElementById('s').textContent=JSON.stringify({observedUpdates:seen,browserNow:new Date(after).toISOString(),browserAgeMs:ms?after-ms:null,fetchMs:Math.round(performance.now()-start),view:view,projection:env},null,2)}catch(e){document.getElementById('s').textContent=String(e)}finally{busy=false;requestAnimationFrame(r)}}r()</script></body></html>"
page_json=$(json_escape "$page")
b1="{\"kind\":\"script.effect\",\"effectType\":\"projection\",\"projectionId\":\"state\",\"snapshotRevision\":\"snap-$ms\",\"artifactRevision\":\"clock.rev.1\",\"sequence\":$ms,\"value\":{\"page\":\"clock\",\"renderedAt\":\"$now\",\"unix\":$secs,\"ms\":$ms,\"seq\":$ms}}"
b2="{\"kind\":\"script.effect\",\"effectType\":\"artifact\",\"artifactName\":\"index.html\",\"artifactRevision\":\"clock.rev.1\",\"mediaType\":\"text/html\",\"body\":\"$page_json\"}"
printf 'Content-Length: %s\r\n\r\n%s' "${#b1}" "$b1"
printf 'Content-Length: %s\r\n\r\n%s' "${#b2}" "$b2"
